sql:
SELECT neighbourhood_name
FROM neighbourhoods
ORDER BY neighbourhood_name;

SELECT neighbourhood_name
FROM neighbourhoods
WHERE borough = 'Scarborough';

SELECT neighbourhood_name
  FROM neighbourhoods
  WHERE crime_rate = (SELECT MAX(crime_rate) FROM neighbourhoods);

SELECT neighbourhood_name
FROM neighbourhoods
ORDER BY population DESC;

